import{_ as i,o as t,c as r,al as a}from"./chunks/framework.DPRzuwkw.js";const _=JSON.parse('{"title":"Datapack","description":"","frontmatter":{"next":{"text":"InWorld Recipe System","link":"/en/posts/docs/datapack/00_inworld_recipe"}},"headers":[],"relativePath":"en/posts/docs/datapack/index.md","filePath":"en/posts/docs/datapack/index.md","lastUpdated":1773840449000}'),n={name:"en/posts/docs/datapack/index.md"};function l(o,e,s,c,p,m){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="datapack" tabindex="-1">Datapack <a class="header-anchor" href="#datapack" aria-label="Permalink to “Datapack”">​</a></h1><p>Datapack support is one of the core features of AnvilCraft, allowing customization of various recipes and mechanics through JSON files. The following documentation will detail the structure, fields, and usage of each recipe type.</p><h2 id="recipes" tabindex="-1">Recipes <a class="header-anchor" href="#recipes" aria-label="Permalink to “Recipes”">​</a></h2><p>These recipe types form the foundation of AnvilCraft&#39;s crafting system:</p><ul><li><a href="./00_inworld_recipe.html">InWorld Recipe</a> - In-world recipe system, triggered by mechanisms like anvils</li><li><a href="./01_item_compress_recipe.html">Item Compress Recipe</a> - Compress multiple items into more advanced items</li><li><a href="./02_block_compress_recipe.html">Block Compress Recipe</a> - Compress multiple blocks into more advanced blocks</li><li><a href="./03_item_crush_recipe.html">Item Crush Recipe</a> - Crush items into smaller items</li><li><a href="./04_block_crush_recipe.html">Block Crush Recipe</a> - Crush blocks into smaller blocks or items</li><li><a href="./05_stamping_recipe.html">Stamping Recipe</a> - Transform items into other items on the stamping platform</li><li><a href="./06_bulging_recipe.html">Bulging Recipe</a> - Bulge items into other items using fluid in cauldrons</li><li><a href="./07_squeezing_recipe.html">Squeezing Recipe</a> - Squeeze blocks into other blocks using fluid in cauldrons</li><li><a href="./08_item_inject_recipe.html">Item Inject Recipe</a> - Inject fluid into items to create new items</li><li><a href="./09_cooking_recipe.html">Cooking Recipe</a> - Cook items into other items using heat sources</li><li><a href="./10_super_heating_recipe.html">Super Heating Recipe</a> - Transform items using high-temperature fluid</li><li><a href="./11_timewarp_recipe.html">Time Warp Recipe</a> - Transform items using time power and fluid</li><li><a href="./12_unpack_recipe.html">Unpack Recipe</a> - Unpack compressed items into original items</li><li><a href="./13_block_smear_recipe.html">Block Smear Recipe</a> - Smear lower blocks using upper blocks</li><li><a href="./14_multiblock_recipe.html">Multiblock Recipe</a> - Define complex multiblock structure recipes</li><li><a href="./15_mob_transform_recipe.html">Mob Transform Recipe</a> - Define transformation rules between mob entities</li><li><a href="./16_jewel_crafting_recipe.html">Jewel Crafting Recipe</a> - Craft various jewelry and decorative items</li><li><a href="./17_mineral_fountain_recipe.html">Mineral Fountain Recipe</a> - Define block transformation rules for mineral fountains</li><li><a href="./18_boiling_recipe.html">Boiling Recipe</a> - Process items with cauldron + lit campfire conditions</li><li><a href="./19_mesh_recipe.html">Mesh Recipe</a> - Filter/transform items through mesh scaffolding</li><li><a href="./20_mass_inject_recipe.html">Mass Inject Recipe</a> - Inject mass value into target items</li><li><a href="./21_stamping_unique_items_recipe.html">Stamping Unique Items Recipe</a> - Stamping recipe with unique (non-duplicate) inputs</li><li><a href="./22_mob_transform_with_item_recipe.html">Mob Transform With Item Recipe</a> - Item-driven probabilistic special mob transformation</li><li><a href="./23_multiblock_conversion_recipe.html">Multiblock Conversion Recipe</a> - Convert a matched structure into another structure</li><li><a href="./24_mineral_fountain_chance_recipe.html">Mineral Fountain Chance Recipe</a> - Dimension-limited probability conversion for mineral fountain</li><li><a href="./25_charger_charging_recipe.html">Charger Charging Recipe</a> - Define charger/discharger processing behavior</li><li><a href="./26_multiple_to_one_smithing_recipe.html">Multiple To One Smithing Recipe</a> - 2/4/8-to-1 multi-input smithing recipes</li><li><a href="./27_neutron_irradiation_recipe.html">Neutron Irradiation Recipe</a> - Process items with neutron irradiator conditions</li><li><a href="./28_permutation_recipe.html">Permutation Recipe</a> - Frost smithing permutation recipe type</li><li><a href="./29_deformation_recipe.html">Deformation Recipe</a> - Frost smithing deformation recipe type</li><li><a href="./30_energy_weapon_make_recipe.html">Energy Weapon Make Recipe</a> - Multi-ingredient energy weapon assembly</li><li><a href="./31_anvil_collision_recipe.html">Anvil Collision Craft Recipe</a> - Trigger conversions by anvil collision speed and targets</li></ul><h2 id="usage-instructions" tabindex="-1">Usage Instructions <a class="header-anchor" href="#usage-instructions" aria-label="Permalink to “Usage Instructions”">​</a></h2><p>To use these recipes, you need to create corresponding JSON files in your datapack and place them in the correct directory structure. Each recipe type has its specific structure and field requirements - please refer to the corresponding documentation for detailed information.</p>',7)])])}const u=i(n,[["render",l]]);export{_ as __pageData,u as default};
